#include <iostream>

class Value {
    int value_;
public:
    explicit Value(int value) : value_(value) {}
    void add(int amount) { value_ += amount; }
    int get() const { return value_; }
};

int main() {
    int value{}, change{};
    if (!(std::cin >> value >> change)) return 1;
    Value original(value);
    Value copy(original);
    copy.add(change);
    std::cout << original.get() << ' ' << copy.get() << '\n';
}
